import{_ as s,c as e,o as t,a2 as a}from"./chunks/framework.CriqKoQt.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"docs/2026上/hoisting-in-pnpm.md","filePath":"docs/2026上/hoisting-in-pnpm.md","lastUpdated":1777364473000}'),p={name:"docs/2026上/hoisting-in-pnpm.md"};function o(i,n,l,d,c,r){return t(),e("div",null,n[0]||(n[0]=[a(`<h2 id="pnpm-的-hoisting-提升" tabindex="-1">pnpm 的 Hoisting（提升） <a class="header-anchor" href="#pnpm-的-hoisting-提升" aria-label="Permalink to &quot;pnpm 的 Hoisting（提升）&quot;">​</a></h2><p>pnpm 的 <strong>hoisting</strong>（提升）是指将深层嵌套的依赖包&quot;提升&quot;到更高层级的 <code>node_modules</code> 目录中，使其能被更多包访问到的机制。</p><h3 id="背景-pnpm-的严格隔离" tabindex="-1">背景：pnpm 的严格隔离 <a class="header-anchor" href="#背景-pnpm-的严格隔离" aria-label="Permalink to &quot;背景：pnpm 的严格隔离&quot;">​</a></h3><p>pnpm 默认采用<strong>严格的依赖隔离</strong>策略：每个包只能访问自己在 <code>package.json</code> 中声明的依赖。这是通过符号链接（symlink）+ 硬链接实现的嵌套结构：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>node_modules/</span></span>
<span class="line"><span>├── .pnpm/                          # 所有包的实际存储位置（扁平结构）</span></span>
<span class="line"><span>│   ├── @html-eslint+parser@0.24.1/</span></span>
<span class="line"><span>│   │   └── node_modules/</span></span>
<span class="line"><span>│   │       └── @html-eslint/parser  # 0.24.1 的实际文件</span></span>
<span class="line"><span>│   ├── @html-eslint+parser@0.59.0/</span></span>
<span class="line"><span>│   │   └── node_modules/</span></span>
<span class="line"><span>│   │       └── @html-eslint/parser  # 0.59.0 的实际文件</span></span>
<span class="line"><span>│   └── @tencent+eslint-config-light-vue3@1.0.14/</span></span>
<span class="line"><span>│       └── node_modules/</span></span>
<span class="line"><span>│           └── @html-eslint/</span></span>
<span class="line"><span>│               └── parser → ../../@html-eslint+parser@0.24.1/...  # 只能看到 0.24.1</span></span>
<span class="line"><span>└── @html-eslint/</span></span>
<span class="line"><span>    └── parser → .pnpm/@html-eslint+parser@0.59.0/...  # 根目录提升的是 0.59.0</span></span></code></pre></div><h3 id="hoisting-的含义" tabindex="-1">Hoisting 的含义 <a class="header-anchor" href="#hoisting-的含义" aria-label="Permalink to &quot;Hoisting 的含义&quot;">​</a></h3><p><strong>Hoisting</strong> 就是把某些包的符号链接放到根目录的 <code>node_modules/</code> 下，让所有包都能&quot;看到&quot;它。pnpm 有两种 hoisting 配置：</p><table tabindex="0"><thead><tr><th>配置项</th><th>作用</th><th>默认值</th></tr></thead><tbody><tr><td><code>hoist</code></td><td>将依赖提升到 <code>node_modules/.pnpm/node_modules/</code> 下（半公开）</td><td><code>true</code></td></tr><tr><td><code>public-hoist-pattern</code></td><td>将依赖提升到根 <code>node_modules/</code> 下（完全公开）</td><td><code>[&#39;*eslint*&#39;, &#39;*prettier*&#39;]</code></td></tr><tr><td><code>shamefully-hoist</code></td><td>将<strong>所有</strong>依赖都提升到根目录（等同于 npm 的行为）</td><td><code>false</code></td></tr></tbody></table><h3 id="和你遇到的问题的关系" tabindex="-1">和你遇到的问题的关系 <a class="header-anchor" href="#和你遇到的问题的关系" aria-label="Permalink to &quot;和你遇到的问题的关系&quot;">​</a></h3><p>在上一轮对话中，我们发现了这个问题：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># ESLint debug 输出：</span></span>
<span class="line"><span>Parser:  @html-eslint/parser@0.24.1   ← 从 @tencent/eslint-config-light-vue3 的上下文解析</span></span>
<span class="line"><span>Plugin:  @html-eslint/eslint-plugin@0.59.0  ← 被 hoist 到根目录，加载了你声明的高版本</span></span></code></pre></div><p>这是因为：</p><ol><li><strong>Plugin 被提升了</strong> — pnpm 默认的 <code>public-hoist-pattern</code> 包含 <code>*eslint*</code>，所以 <code>@html-eslint/eslint-plugin@0.59.0</code> 被提升到了根 <code>node_modules/</code>，ESLint 加载 plugin 时找到了 0.59.0</li><li><strong>Parser 没被正确提升</strong> — ESLint 加载 parser 时，是从 <code>@tencent/eslint-config-light-vue3/lib/html.js</code> 的路径上下文去 resolve <code>@html-eslint/parser</code> 的，pnpm 的隔离机制让它找到了 <code>@tencent/eslint-config-light-vue3</code> 自己依赖的 <strong>0.24.1</strong>，而不是你项目根目录声明的 0.59.0</li></ol><h3 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h3><blockquote><p><strong>pnpm 的 hoisting = 把嵌套的依赖提升到更高层级，让更多包能访问到它。</strong> 它是 pnpm 在&quot;严格隔离&quot;和&quot;兼容性&quot;之间的折中方案。你遇到的 ESLint 报错，正是因为 hoisting 机制导致 parser 和 plugin 被解析到了不同版本。</p></blockquote>`,15)]))}const g=s(p,[["render",o]]);export{m as __pageData,g as default};
